import java.io.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Properly handle user input by encoding it before outputting to the webpage
            String encodedInput = Encode.forHtml(userInput);
            System.out.println("<p>Welcome, " + encodedInput + "!</p>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
